export const Amounts = () => {
  const { t } = useTranslation('actionPagesBuilder');
  const { t: tCommon } = useTranslation('common');
  const { watch } = useFormContext<ActionPageDetailFormValues>();
  const configurationSelectorProps = useAmountConfigurations();
  const amountPresets = watch('amountConfiguration.amountPresets.default');
  const amountPresetsLoaded = Boolean(amountPresets);
  const amountPresetsOther = watch('amountConfiguration.amountPresetsOther');
  // Campaign Parity: users can now disable both Amount Presets and Other Amount,
  // allowing entry of custom amounts for each fund with no allocation limitations.
  const isCampaignParity = (amountPresets ?? []).length === 0 && !amountPresetsOther;
  const isLoaded = amountPresetsLoaded && !configurationSelectorProps?.isLoading;

  return (
    <ConfigurationPanel {...configurationSelectorProps}>
      <Stack spacing={6}>
        {!isCampaignParity && (
          <Skeleton isLoaded={isLoaded}>
            <FrequencyOptions />
          </Skeleton>
        )}

        <Stack spacing={6}>
          <Flex flexDirection="column" gap={1}>
            <Label variant="medium">{t('amountsPanel.amountsConfiguration')}</Label>
            <Label color="neutral.400" variant="medium">
              {t('amountsPanel.description')}
            </Label>
          </Flex>
        </Stack>
        <Skeleton isLoaded={isLoaded}>
          <Stack>
            <FieldArray name="amountConfiguration.amountPresets.default">
              {({ append, fields, move, remove }) => (
                <>
                  <DragDrop
                    id="amountPresets.default"
                    onDragEnd={({ destination, source }) => {
                      if (destination) {
                        move(source.index, destination?.index);
                      }
                    }}
                  >
                    {fields.map((field, index) => {
                      return (
                        <DragDrop.Item id={field.id} index={index} key={field.id} py={1}>
                          <AmountPresetItem
                            inputLeftLabel={t('designer.finance.amounts.amount')}
                            inputLeftName={`amountConfiguration.amountPresets.default.${index}.amount`}
                            inputRightLabel={t('designer.finance.amounts.descriptionOptional')}
                            inputRightName={`amountConfiguration.amountPresets.default.${index}.description`}
                            onDelete={() => {
                              remove(index);
                            }}
                          />
                        </DragDrop.Item>
                      );
                    })}
                  </DragDrop>
                  <Button
                    leftIcon={fields?.length > 0 ? <AddIcon /> : undefined}
                    mt={1}
                    onClick={() => {
                      if (fields.length === 0) {
                        append({
                          amount: '25',
                          description: '',
                          id: v4(),
                        });
                        append({
                          amount: '50',
                          description: '',
                          id: v4(),
                        });
                        append({
                          amount: '100',
                          description: '',
                          id: v4(),
                        });
                        append({
                          amount: '200',
                          description: '',
                          id: v4(),
                        });
                      } else {
                        append({
                          amount: '',
                          description: '',
                          id: v4(),
                        });
                      }
                    }}
                    variant="secondary"
                  >
                    {!fields || fields.length === 0
                      ? t('designer.finance.amounts.enablePresets')
                      : t('designer.finance.amounts.addAmount')}
                  </Button>
                </>
              )}
            </FieldArray>
          </Stack>
        </Skeleton>
        {/* <Stack>
                <Label variant="bold">{t('designer.finance.amounts.defaultAmount')}</Label>
                <Meta variant="regular">{t('designer.finance.amounts.defaultAmountSubtitle')}</Meta>
                <SelectControl
                  label={tCommon('amount')}
                  name="amountConfiguration.defaultAmount"
                  onChange={(event) => {
                    setDefaultValue(event.target.value);
                  }}
                  options={defaultAmountOptions}
                  placeholder={t('designer.finance.amounts.chooseDefaultAmount')}
                  value={selectedDefaultPreset?.id}
                />
              </Stack> */}
        <FormRadioGroup
          isRequired
          label={t('designer.finance.amounts.allowOtherAmounts')}
          name="amountConfiguration.amountPresetsOther"
        >
          <Flex gap={4}>
            <RadioControl isDefault value="true">
              {tCommon('yes')}
            </RadioControl>
            <RadioControl value="false">{tCommon('no')}</RadioControl>
          </Flex>
        </FormRadioGroup>
        <Featured />
        <Divider />
        <Flex flexDirection="column" gap={4} justify="stretch" marginTop={4}>
          <Heading as="h4" textStyle="H4Bold">
            {t('designer.finance.otherRecurringOptions')}
          </Heading>
          <Flex flexDirection="column" gap={6} width="full">
            <RecurringCheckboxConfiguration />
            <RecurringUpgrade />
          </Flex>
        </Flex>
        <Divider />
        <Flex flexDirection="column" gap={6} justify="stretch" marginTop={4}>
          <Heading as="h4" textStyle="H4Bold">
            {t('paymentPanel.transactionLimits.title')}
          </Heading>
          <FormMaskedInputControl
            formHelperText={t('paymentPanel.transactionLimits.perTransactionMinimum.description')}
            isRequired
            label={t('paymentPanel.transactionLimits.perTransactionMinimum.title')}
            name="amountConfiguration.transactionMinimum"
            type="currency"
          />
          <FormMaskedInputControl
            formHelperText={t('paymentPanel.transactionLimits.perTransactionMaximum.description')}
            isRequired
            label={t('paymentPanel.transactionLimits.perTransactionMaximum.title')}
            name="amountConfiguration.transactionMaximum"
            type="currency"
          />
        </Flex>
        <Divider />
        <FuturePledge />
      </Stack>
    </ConfigurationPanel>
  );
};

