import { Flex, IconButton, Stack, useColorModeValue } from '@chakra-ui/react';
import { ActionPageDetailFormValues } from '@domain/actionPages';
import { IOption } from '@domain/constants';
import { SourceFrequency } from '@domain/entry';
import { useFeatureFlag } from '@state/featureFlags';
import { DeleteIcon } from '@ui/assets/icons/DeleteIcon';
import { FormSelectControl } from '@ui/components/formControls/SelectControl';
import { OrderOfSourceFrequencies } from '@ui/components/organisms/Funds';
import { Panel } from '@ui/components/Panel';
import { Label, Meta } from '@ui/components/typography';
import { useGetAccountId } from '@utils/useGetAccountId';
import { useCallback, useEffect, useMemo } from 'react';
import { useFormContext } from 'react-hook-form';
import { useTranslation } from 'react-i18next';
import { AddFrequencyOptionMenu } from './AddFrequencyOptionMenu/AddFrequencyOptionMenu';

const RecurringOptionLabel = ({ opt }: { opt: IOption }) => {
  const { t } = useTranslation('common');
  const iconColor = useColorModeValue('neutral.600', 'neutral.500');
  const { setValue, watch } = useFormContext<ActionPageDetailFormValues>();
  const recurringOptions = watch('amountConfiguration.recurringOptions');

  const onClick = useCallback(() => {
    const options = (recurringOptions || [])
      .filter((o) => o !== opt.value)
      .sort((a, b) => OrderOfSourceFrequencies.indexOf(a) - OrderOfSourceFrequencies.indexOf(b));

    setValue('amountConfiguration.recurringOptions', options);
  }, [opt, recurringOptions, setValue]);

  return (
    <Flex alignItems="center" justifyContent="space-between">
      <Label variant="medium">{opt.label}</Label>
      {(recurringOptions || []).length > 1 ? (
        <IconButton
          alignItems="center"
          aria-label={t('button.delete')}
          color={iconColor}
          display="flex"
          icon={<DeleteIcon height="12px" w="12px" />}
          justifyContent="center"
          onClick={onClick}
          size="xs"
          variant="unstyled"
        />
      ) : null}
    </Flex>
  );
};

export const FrequencyOptions = () => {
  const { t } = useTranslation(['common', 'actionPagesBuilder']);
  const { setValue, watch } = useFormContext<ActionPageDetailFormValues>();
  const recurringOptions = watch('amountConfiguration.recurringOptions');
  const recurringDefaultFrequency = watch('amountConfiguration.recurringDefaultFrequency');
  const accountId = useGetAccountId();

  const enableDefaultFrequency = useFeatureFlag(
    'actionPages.enableDefaultFrequency',
    false,
    accountId
  );

  const selectedRecurringOptions = useMemo(
    () =>
      recurringOptions
        ?.sort((a, b) => OrderOfSourceFrequencies.indexOf(a) - OrderOfSourceFrequencies.indexOf(b))
        ?.map((opt) => ({
          label: t(`common:frequency.recurring.${opt}`),
          value: opt.toString(),
        })) || [],
    [recurringOptions, t]
  );

  useEffect(() => {
    if (!recurringOptions?.includes(recurringDefaultFrequency as SourceFrequency)) {
      setValue('amountConfiguration.recurringDefaultFrequency', recurringOptions?.[0]);
    }
  }, [recurringDefaultFrequency, recurringOptions, setValue]);

  return (
    <Stack spacing={2}>
      <Label variant="bold">{t('actionPagesBuilder:amountsPanel.frequencyOptions')}</Label>
      <Meta color="neutral.400" lineHeight="18px" variant="regular">
        {t('actionPagesBuilder:amountsPanel.max', { count: 4 })}
      </Meta>
      <Panel display="flex" flexDirection="column" gap={4} padding={4} variant="secondary">
        {selectedRecurringOptions.map((opt) => (
          <RecurringOptionLabel key={opt.value} opt={opt} />
        ))}
        {(recurringOptions || []).length < 4 ? <AddFrequencyOptionMenu /> : null}
      </Panel>
      {enableDefaultFrequency ? (
        <FormSelectControl
          label={t('actionPagesBuilder:recurringPanel.defaultFrequency')}
          name="amountConfiguration.recurringDefaultFrequency"
          options={selectedRecurringOptions}
          placeholder={t('actionPagesBuilder:designer.finance.amounts.chooseDefaultFrequency')}
          variant="floating"
        />
      ) : null}
    </Stack>
  );
};

