import { Flex } from '@chakra-ui/react';
import { ActionPageDetailFormValues } from '@domain/actionPages';
import { SelectControl } from '@ui/components/formControls/SelectControl';
import { Label, Meta } from '@ui/components/typography';
import { useCallback, useMemo } from 'react';
import { useFormContext } from 'react-hook-form';
import { useTranslation } from 'react-i18next';

export const Featured = () => {
  const { t } = useTranslation('actionPagesBuilder', {
    keyPrefix: 'designer.finance.amounts',
  });
  const { t: tCommon } = useTranslation('common');
  const { setValue, watch } = useFormContext<ActionPageDetailFormValues>();
  const presets = watch('amountConfiguration.amountPresets.default');
  const presetsWithDefault = useMemo(() => presets || [], [presets]);
  const featuredPreset = useMemo(() => presets?.find((p) => p.featured), [presets]);

  const handleAmountChange = useCallback(
    (e) => {
      setValue(
        `amountConfiguration.amountPresets.default`,
        presetsWithDefault.map((p) =>
          p.id === e.target.value
            ? {
                ...p,
                featured: true,
                featuredLabel: featuredPreset?.featuredLabel,
              }
            : { ...p, featured: false, featuredLabel: undefined }
        )
      );
    },
    [setValue, presetsWithDefault, featuredPreset?.featuredLabel]
  );

  const handleLabelChange = useCallback(
    (e) => {
      setValue(
        `amountConfiguration.amountPresets.default`,
        presetsWithDefault.map((p) =>
          p.id === featuredPreset?.id
            ? {
                ...p,
                featured: true,
                featuredLabel: e.target.value,
              }
            : p
        )
      );
    },
    [setValue, presetsWithDefault, featuredPreset?.id]
  );

  return (
    <Flex flexDirection="column" gap={3}>
      <Label variant="bold">{t('featured.title')}</Label>
      <Meta>{t('featured.description')}</Meta>
      <Flex gap={2}>
        <SelectControl
          label={t('amount')}
          name="featuredAmount"
          onChange={handleAmountChange}
          options={presetsWithDefault?.map((p) => ({
            label: p.amount?.toString() ?? '',
            value: p.id ?? '',
          }))}
          placeholder="-"
          value={featuredPreset?.id ?? ''}
        />
        <SelectControl
          isDisabled={!featuredPreset}
          label={tCommon('label')}
          name="featuredAmountLabel"
          onChange={handleLabelChange}
          options={[
            { label: 'None', value: '' },
            { label: 'Popular', value: 'Popular' },
          ]}
          value={featuredPreset?.featuredLabel ?? ''}
        />
      </Flex>
    </Flex>
  );
};

