import {
  FormControl as ChakraFormControl,
  FormControlProps as ChakraFormControlProps,
  FormErrorMessage,
  FormHelperText,
  FormLabel,
  FormLabelProps,
} from '@chakra-ui/react';
import React, { ReactNode, useMemo } from 'react';
import { normalizeError, YupError } from '../hooks/useControl/useControl';

export type FormControlProps = Overwrite<
  ChakraFormControlProps,
  { label?: React.ReactNode | string; variant?: string }
> & {
  children: ReactNode;
  error?: YupError;
  errorPosition?: 'top' | 'bottom';
  formHelperText?: React.ReactNode;
  formHelperTextProps?: ChakraFormControlProps;
  formLabelProps?: FormLabelProps;
  isInvalid?: boolean;
  isTouched?: boolean;
  name?: string;
  testid?: string;
};

export const FormControl = (props: FormControlProps): JSX.Element => {
  const {
    children,
    className,
    error,
    errorPosition = 'bottom',
    formHelperText,
    formHelperTextProps,
    formLabelProps,
    isInvalid = false,
    isTouched,
    label,
    name,
    testid,
    variant,
    ...rest
  } = props;

  const safeIsTouched = isTouched === undefined || isTouched;

  const customClassName = useMemo(
    () => [className, 'form-control', `form-control-${name}`].filter(Boolean).join(' '),
    [name, className]
  );

  const errorString = normalizeError(error);

  return (
    <ChakraFormControl
      className={customClassName}
      isInvalid={isInvalid && safeIsTouched}
      variant={variant}
      {...rest}
    >
      {label && variant !== 'floating' && (
        <FormLabel display="flex" htmlFor={name} pointerEvents="none" {...formLabelProps}>
          {label}
        </FormLabel>
      )}
      {!!errorString && errorPosition === 'top' && safeIsTouched && (
        <FormErrorMessage data-testid={testid ? `${testid}-error` : undefined} mb={2}>
          {normalizeError(error)}
        </FormErrorMessage>
      )}
      {children}
      {/* To use the css selector `+` we need the label to be after the inputs, only relevant for floating */}
      {label && variant === 'floating' && (
        <FormLabel display="flex" htmlFor={name} pointerEvents="none" {...formLabelProps}>
          {label}
        </FormLabel>
      )}
      {formHelperText && <FormHelperText {...formHelperTextProps}>{formHelperText}</FormHelperText>}
      {!!errorString && errorPosition === 'bottom' && safeIsTouched && (
        <FormErrorMessage data-testid={testid ? `${testid}-error` : undefined}>
          {errorString}
        </FormErrorMessage>
      )}
    </ChakraFormControl>
  );
};

