import { useGetAccountConfiguration } from '@state/accountConfiguration';
import { useEffect, useMemo } from 'react';
import { useFormContext } from 'react-hook-form';
import { Navigate, useLocation } from 'react-router-dom';
import { ActionPageRouteOption } from '../../hooks/useActionPagesBuilderNavigation';
import { DesignerPanel } from '../components';
import { Amounts } from './Amounts';
import { Funds } from './Funds';
import { Payment } from './Payment';
import { Product } from './Product/Product';

export const actionPagesFinanceRoutes: () => ActionPageRouteOption[] = () => [
  {
    element: <Amounts />,
    label: 'amounts',
    path: `amounts`,
  },
  {
    element: <Funds />,
    label: 'funds',
    path: `funds`,
  },
  {
    element: <Payment />,
    label: 'payment',
    path: `payment`,
  },
  {
    element: <Product />,
    label: 'product',
    path: `product`,
  },
];

export const Finance = () => {
  const location = useLocation();
  const { accountConfiguration } = useGetAccountConfiguration();
  const { watch } = useFormContext();
  const pageType = watch('pageType');

  const routes = useMemo(() => {
    const childRoutes = actionPagesFinanceRoutes();

    if (pageType === 'storefront') {
      childRoutes.shift();
    }

    if (!accountConfiguration?.apGoaaEnabled || pageType === 'storefront') {
      childRoutes.pop();
    }

    return childRoutes;
  }, [accountConfiguration?.apGoaaEnabled, pageType]);

  // Scroll to Finance Preview upon Mount
  useEffect(() => {
    document.querySelector(`#preview-block-finance`)?.scrollIntoView({ behavior: 'smooth' });
  }, []);

  if (location.pathname.split('/').pop() === 'finance') {
    return <Navigate replace to={routes[0].path} />;
  }

  return <DesignerPanel routes={routes} />;
};

